// src/pages/SellerDashboard.js
import React, { useState } from "react";
import axios from "axios";
import "./SellerDashboard.css";

function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({
    name: "",
    description: "",
    category: "Earphone",
    price: "",
    offerPrice: "",
    image: "" // added image field
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // send product to backend
      const res = await axios.post("http://localhost:5000/api/products", form);
      setProducts([...products, res.data]); // update local list
      setForm({ name: "", description: "", category: "Earphone", price: "", offerPrice: "", image: "" });
      alert("✅ Product added successfully!");
    } catch (err) {
      console.error(err);
      alert("❌ Failed to add product");
    }
  };

  return (
    <div className="seller-dashboard">
      {/* Sidebar */}
      <aside className="sidebar">
        <h1 className="logo"></h1>
        <nav>
          <ul>
            <li className="active">➕ Add Product</li>
            <li>📦 Product List</li>
            <li>📝 Orders</li>
          </ul>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        <h2 className="page-title">Add Product</h2>

        {/* Form */}
        <form className="product-form" onSubmit={handleSubmit}>
          <label>Product Name</label>
          <input
            type="text"
            name="name"
            placeholder="Type here"
            value={form.name}
            onChange={handleChange}
            required
          />

          <label>Product Description</label>
          <textarea
            name="description"
            placeholder="Type here"
            value={form.description}
            onChange={handleChange}
          ></textarea>

          <label>Image URL</label>
          <input
            type="text"
            name="image"
            placeholder="https://..."
            value={form.image}
            onChange={handleChange}
            required
          />

          <div className="row">
            <div>
              <label>Category</label>
              <select name="category" value={form.category} onChange={handleChange}>
                <option>Earphone</option>
                <option>Smartphone</option>
                <option>Laptop</option>
                <option>Smartwatch</option>
                <option>Other</option>
              </select>
            </div>

            <div>
              <label>Product Price</label>
              <input
                type="number"
                name="price"
                placeholder="0"
                value={form.price}
                onChange={handleChange}
                required
              />
            </div>

            <div>
              <label>Offer Price</label>
              <input
                type="number"
                name="offerPrice"
                placeholder="0"
                value={form.offerPrice}
                onChange={handleChange}
              />
            </div>
          </div>

          <button type="submit" className="add-btn">ADD</button>
        </form>

        {/* Seller's products */}
        <h3 className="list-title">Your Listed Items</h3>
        <div className="product-list">
          {products.map((p, idx) => (
            <div key={idx} className="product-card">
              <h4>{p.name}</h4>
              <p>{p.description}</p>
              <p><b>Category:</b> {p.category}</p>
              <p><b>Price:</b> ₹{p.price}</p>
              {p.offerPrice && <p><b>Offer:</b> ₹{p.offerPrice}</p>}
              {p.image && <img src={p.image} alt={p.name} width="120" />}
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default SellerDashboard;
